    #[test]
    fn fold_autonomic_cost_charged() {
        let state = default_state();
        let event = AutonomicEvent::CostCharged {
            amount_micro_credits: 500,
            reason: autonomic_core::CostReason::ModelInference {
                model: "sonnet".into(),
