                rationale: "tight".into(),
                ..GatingDecision::noop("r2")
            }),
        }));

        let state = HomeostaticState::for_agent("test");
        let profile = evaluate(&state, &rules);
        assert_eq!(profile.economic.preferred_model, Some(ModelTier::Budget));
    }
